UPDATE STOCVNGL SET
    BLOCK_FLAG = '1'
    , BLOCK_REASON = #{BLOCK_REASON}
    , MOD_USER_ID = #{ses.userId}
    , MOD_DATE = SYSDATE
WHERE GATE_CD  = #{ses.gateCd}
  AND VENDOR_CD = #{VENDOR_CD}

UPDATE STOCVNGL SET
    BLOCK_FLAG = '0'
    , BLOCK_REASON = ''
    , MOD_USER_ID = #{ses.userId}
    , MOD_DATE = SYSDATE
WHERE GATE_CD  = #{ses.gateCd}
  AND VENDOR_CD = #{VENDOR_CD}
